import scala.collection.mutable.ListBuffer

object Solution {
  def solve(n: Long): Long = {
    val specialNumbers = ListBuffer[Long]()

    for (length <- 1 to 20) {
      for (a <- 0 to length) {
        for (b <- 0 to (length - a) / 2) {
          val remaining = length - a - 2 * b
          if (remaining >= 0 && remaining % 3 == 0) {
            val c = remaining / 3
            var digits = ListBuffer[(Int, Int)]()
            if (a > 0) digits += ((1, a))
            if (b > 0) digits += ((2, b))
            if (c > 0) digits += ((3, c))

            val halfLen = (length + 1) / 2
            val oddDigits = digits.filter { case (d, cnt) => cnt % 2 == 1 }.map(_._1).toList

            if (length % 2 == 1) {
              if (oddDigits.size != 1) {
                // Skip if not exactly one odd count digit for odd length
              } else {
                val middleDigit = oddDigits.head
                val newDigits = digits.map { case (d, cnt) =>
                  if (d == middleDigit) (d, cnt - 1) else (d, cnt)
                }.filter { case (_, cnt) => cnt > 0 }

                generatePalindromes(newDigits.toList, halfLen - 1, middleDigit, length, specialNumbers)
              }
            } else {
              if (oddDigits.nonEmpty) {
                // Skip if any odd count digits for even length
              } else {
                generatePalindromes(digits.toList, halfLen, -1, length, specialNumbers)
              }
            }
          }
        }
      }
    }

    val sortedNumbers = specialNumbers.distinct.sorted
    sortedNumbers.find(_ > n).getOrElse(-1L)
  }

  private def generatePalindromes(
    digits: List[(Int, Int)],
    halfLen: Int,
    middleDigit: Int,
    length: Int,
    specialNumbers: ListBuffer[Long]
  ): Unit = {
    val digitList = digits.flatMap { case (d, cnt) => List.fill(cnt / 2)(d) }
    val uniqueDigits = digitList.distinct
    val counts = uniqueDigits.map(d => digitList.count(_ == d)).toArray
    val current = new Array[Int](halfLen)
    val used = new Array[Int](uniqueDigits.size)

    def backtrack(pos: Int): Unit = {
      if (pos == halfLen) {
        val firstHalf = current.take(halfLen).toList
        val palindrome = if (middleDigit != -1) {
          firstHalf ::: List(middleDigit) ::: firstHalf.reverse
        } else {
          firstHalf ::: firstHalf.reverse
        }
        val num = palindrome.mkString.toLong
        specialNumbers += num
      } else {
        for (i <- uniqueDigits.indices) {
          if (used(i) < counts(i)) {
            used(i) += 1
            current(pos) = uniqueDigits(i)
            backtrack(pos + 1)
            used(i) -= 1
          }
        }
      }
    }

    backtrack(0)
  }
}
